                else
                    writer.WriteNull("issuer");

            if (currency.CurrencyTypeOption.IsSet)
                if (currency.CurrencyTypeOption.Value != null)
                    writer.WriteString("currencyType", currency.CurrencyType);
                else
                    writer.WriteNull("currencyType");

            if (currency.TagsOption.IsSet)
                if (currency.TagsOption.Value != null)
                    writer.WriteString("tags", currency.Tags);
                else
                    writer.WriteNull("tags");

            if (currency.StatusOption.IsSet)
                writer.WriteBoolean("status", currency.StatusOption.Value.Value);

            if (currency.EnableVirtualRechargeOption.IsSet)
                writer.WriteBoolean("enableVirtualRecharge", currency.EnableVirtualRechargeOption.Value.Value);

            if (currency.EnableVirtualConsumeOption.IsSet)
                writer.WriteBoolean("enableVirtualConsume", currency.EnableVirtualConsumeOption.Value.Value);

            if (currency.DescriptionOption.IsSet)
                if (currency.DescriptionOption.Value != null)
                    writer.WriteString("description", currency.Description);
                else
                    writer.WriteNull("description");

            if (currency.FiatExchangeRateOption.IsSet)
                writer.WriteNumber("fiatExchangeRate", currency.FiatExchangeRateOption.Value.Value);

            if (currency.FiatDailyRechargeLimitOption.IsSet)
                writer.WriteNumber("fiatDailyRechargeLimit", currency.FiatDailyRechargeLimitOption.Value.Value);

            if (currency.TotalSupplyOption.IsSet)
                writer.WriteNumber("totalSupply", currency.TotalSupplyOption.Value.Value);

            if (currency.CreateDateOption.IsSet)
                writer.WriteString("createDate", currency.CreateDateOption.Value.Value.ToString(CreateDateFormat));

            if (currency.LastUpdateOption.IsSet)
                writer.WriteString("lastUpdate", currency.LastUpdateOption.Value.Value.ToString(LastUpdateFormat));
        }
    }
}
